<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    :root {
      color-scheme: light;
      --background: #f3f5f9;
      --surface: #ffffff;
      --border: #e2e7ef;
      --text: #172033;
      --muted: #6b7280;
      --primary: #5568f3;
      --primary-dark: #4052db;
      --danger: #e34d59;
      --shadow: 0 7px 20px rgba(30, 41, 59, 0.07);
    }

    * {
      box-sizing: border-box;
    }

    body {
      min-height: 100vh;
      margin: 0;
      background:
        radial-gradient(circle at top left, rgba(85, 104, 243, 0.1), transparent 30rem),
        var(--background);
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    .app {
      width: min(1180px, calc(100% - 32px));
      margin: 0 auto;
      padding: 48px 0;
    }

    .topbar {
      display: flex;
      align-items: end;
      justify-content: space-between;
      gap: 24px;
      margin-bottom: 28px;
    }

    .heading h1 {
      margin: 0 0 6px;
      font-size: clamp(1.8rem, 4vw, 2.5rem);
      letter-spacing: -0.04em;
    }

    .heading p {
      margin: 0;
      color: var(--muted);
    }

    .new-card-form {
      display: flex;
      width: min(100%, 450px);
      padding: 5px;
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 14px;
      box-shadow: var(--shadow);
    }

    #new-card {
      min-width: 0;
      flex: 1;
      border: 0;
      outline: 0;
      padding: 11px 13px;
      background: transparent;
      color: var(--text);
      font: inherit;
    }

    #new-card::placeholder {
      color: #9aa3b2;
    }

    #add-card {
      border: 0;
      border-radius: 10px;
      padding: 10px 17px;
      background: var(--primary);
      color: #fff;
      font: inherit;
      font-weight: 700;
      cursor: pointer;
      transition: background 160ms ease, transform 160ms ease;
    }

    #add-card:hover {
      background: var(--primary-dark);
    }

    #add-card:active {
      transform: scale(0.97);
    }

    .board {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 20px;
      align-items: start;
    }

    .column {
      min-height: 420px;
      padding: 16px;
      background: rgba(255, 255, 255, 0.7);
      border: 1px solid var(--border);
      border-radius: 18px;
      transition: border-color 160ms ease, background 160ms ease, transform 160ms ease;
    }

    .column.drag-over {
      background: rgba(85, 104, 243, 0.08);
      border-color: var(--primary);
      transform: translateY(-2px);
    }

    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 15px;
      padding: 2px 3px;
    }

    .column-header h2 {
      margin: 0;
      font-size: 1rem;
      letter-spacing: -0.01em;
    }

    .count {
      display: inline-grid;
      min-width: 28px;
      height: 28px;
      place-items: center;
      padding: 0 8px;
      border-radius: 999px;
      background: #e9ecf4;
      color: #4b5563;
      font-size: 0.82rem;
      font-weight: 800;
    }

    .card-list {
      display: flex;
      min-height: 340px;
      flex-direction: column;
      gap: 12px;
    }

    .card {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 12px;
      padding: 15px;
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 13px;
      box-shadow: var(--shadow);
      cursor: grab;
      transition: opacity 150ms ease, transform 150ms ease, box-shadow 150ms ease;
    }

    .card:hover {
      transform: translateY(-2px);
      box-shadow: 0 10px 24px rgba(30, 41, 59, 0.11);
    }

    .card.dragging {
      opacity: 0.45;
      cursor: grabbing;
    }

    .card-title {
      min-width: 0;
      margin: 1px 0;
      overflow-wrap: anywhere;
      line-height: 1.45;
    }

    .card-del {
      display: grid;
      width: 28px;
      height: 28px;
      flex: 0 0 auto;
      place-items: center;
      padding: 0;
      border: 0;
      border-radius: 8px;
      background: transparent;
      color: #9aa3b2;
      font-size: 1.25rem;
      line-height: 1;
      cursor: pointer;
      transition: color 150ms ease, background 150ms ease;
    }

    .card-del:hover {
      background: #fff0f1;
      color: var(--danger);
    }

    @media (max-width: 800px) {
      .app {
        padding: 28px 0;
      }

      .topbar {
        align-items: stretch;
        flex-direction: column;
      }

      .new-card-form {
        width: 100%;
      }

      .board {
        grid-template-columns: 1fr;
      }

      .column {
        min-height: 220px;
      }

      .card-list {
        min-height: 140px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <header class="topbar">
      <div class="heading">
        <h1>Kanban Board</h1>
        <p>Organize your work and keep things moving.</p>
      </div>

      <form class="new-card-form" id="new-card-form">
        <input
          id="new-card"
          type="text"
          placeholder="Add a new task…"
          autocomplete="off"
          aria-label="New card title"
        >
        <button id="add-card" type="submit">Add card</button>
      </form>
    </header>

    <section class="board" aria-label="Kanban board">
      <section class="column" id="col-todo" data-column="todo">
        <header class="column-header">
          <h2>To Do</h2>
          <span class="count" aria-label="0 cards">0</span>
        </header>
        <div class="card-list" aria-label="To Do cards"></div>
      </section>

      <section class="column" id="col-doing" data-column="doing">
        <header class="column-header">
          <h2>Doing</h2>
          <span class="count" aria-label="0 cards">0</span>
        </header>
        <div class="card-list" aria-label="Doing cards"></div>
      </section>

      <section class="column" id="col-done" data-column="done">
        <header class="column-header">
          <h2>Done</h2>
          <span class="count" aria-label="0 cards">0</span>
        </header>
        <div class="card-list" aria-label="Done cards"></div>
      </section>
    </section>
  </main>

  <script>
    (() => {
      "use strict";

      const STORAGE_KEY = "kanban-board-state";
      const columns = [...document.querySelectorAll(".column")];
      const form = document.getElementById("new-card-form");
      const input = document.getElementById("new-card");
      let draggedCard = null;

      function makeId() {
        return "card-" + Date.now() + "-" + Math.random().toString(36).slice(2, 9);
      }

      function updateCounts() {
        columns.forEach((column) => {
          const total = column.querySelectorAll(".card").length;
          const count = column.querySelector(".count");
          count.textContent = total;
          count.setAttribute("aria-label", `${total} card${total === 1 ? "" : "s"}`);
        });
      }

      function saveBoard() {
        const state = [];

        columns.forEach((column) => {
          column.querySelectorAll(".card").forEach((card) => {
            state.push({
              id: card.id,
              title: card.querySelector(".card-title").textContent,
              column: column.dataset.column
            });
          });
        });

        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
        } catch (error) {
          console.warn("Unable to save the board.", error);
        }
      }

      function createCard(title, id = makeId()) {
        const card = document.createElement("article");
        card.className = "card";
        card.id = id;
        card.draggable = true;

        const titleElement = document.createElement("span");
        titleElement.className = "card-title";
        titleElement.textContent = title;

        const deleteButton = document.createElement("button");
        deleteButton.className = "card-del";
        deleteButton.type = "button";
        deleteButton.textContent = "×";
        deleteButton.setAttribute("aria-label", `Delete ${title}`);

        deleteButton.addEventListener("click", () => {
          card.remove();
          updateCounts();
          saveBoard();
        });

        card.addEventListener("dragstart", (event) => {
          draggedCard = card;
          card.classList.add("dragging");
          event.dataTransfer.effectAllowed = "move";
          event.dataTransfer.setData("text/plain", card.id);
        });

        card.addEventListener("dragend", () => {
          draggedCard = null;
          card.classList.remove("dragging");
          columns.forEach((column) => column.classList.remove("drag-over"));
        });

        card.append(titleElement, deleteButton);
        return card;
      }

      function restoreBoard() {
        let state = [];

        try {
          const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
          if (Array.isArray(saved)) {
            state = saved;
          }
        } catch (error) {
          console.warn("Unable to restore the board.", error);
        }

        state.forEach((item) => {
          if (
            !item ||
            typeof item.title !== "string" ||
            typeof item.column !== "string"
          ) {
            return;
          }

          const column = document.querySelector(
            `.column[data-column="${CSS.escape(item.column)}"]`
          );

          if (column) {
            const id = typeof item.id === "string" && item.id ? item.id : makeId();
            column.querySelector(".card-list").append(createCard(item.title, id));
          }
        });

        updateCounts();
      }

      form.addEventListener("submit", (event) => {
        event.preventDefault();
        const title = input.value.trim();

        if (!title) {
          return;
        }

        document
          .querySelector("#col-todo .card-list")
          .append(createCard(title));

        input.value = "";
        input.focus();
        updateCounts();
        saveBoard();
      });

      columns.forEach((column) => {
        column.addEventListener("dragover", (event) => {
          event.preventDefault();
          event.dataTransfer.dropEffect = "move";
          column.classList.add("drag-over");
        });

        column.addEventListener("dragenter", (event) => {
          event.preventDefault();
          column.classList.add("drag-over");
        });

        column.addEventListener("dragleave", (event) => {
          if (!column.contains(event.relatedTarget)) {
            column.classList.remove("drag-over");
          }
        });

        column.addEventListener("drop", (event) => {
          event.preventDefault();
          column.classList.remove("drag-over");

          const cardId = event.dataTransfer.getData("text/plain");
          const card = draggedCard || document.getElementById(cardId);

          if (card && card.classList.contains("card")) {
            column.querySelector(".card-list").append(card);
            updateCounts();
            saveBoard();
          }
        });
      });

      restoreBoard();
    })();
  </script>
</body>
</html>
